#include<bits/stdc++.h>
using namespace std;
bool flag[20000010];
int nxt[20000010];
int main()
{
	memset(flag,true,sizeof(flag));
	for(int i=1;i<=20000000;i++)
	{
		if(!flag[i])
		{
			continue;
		}
		int x=i,flag1=1;
		while(x)
		{
			if(x%10==7)
			{
				flag1=0;
				break;
			}
			x/=10;
		}
		if(!flag1)
		{
			for(int j=i;j<=20000000;j+=i)
			{
				flag[j]=false;
			}
		}
	}
    for(int i=20000000;i>=1;i--)
    {
        if(flag[i])
        {
            nxt[i]=i;
        }
        else
        {
            nxt[i]=nxt[i+1];
        }
    }
	int t;
	scanf("%d",&t);
	while(t--)
	{
		int x;
		scanf("%d",&x);
		if(!flag[x])
		{
			printf("-1\n");
			continue;
		}
		printf("%d\n",nxt[x+1]);
	}
	return 0;
}
